/**
 * @summary Submit quiz answers
 */
export const getSubmitAssessmentUrl = (assessmentId: number) => {
  return `/api/assessments/${assessmentId}/submit`;
};

export const submitAssessment = async (
  assessmentId: number,
  assessmentSubmission: AssessmentSubmission,
  options?: RequestInit,
): Promise<AssessmentResult> => {
  return customFetch<AssessmentResult>(getSubmitAssessmentUrl(assessmentId), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(assessmentSubmission),
  });
};

export const getSubmitAssessmentMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof submitAssessment>>,
    TError,
    { assessmentId: number; data: BodyType<AssessmentSubmission> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof submitAssessment>>,
  TError,
  { assessmentId: number; data: BodyType<AssessmentSubmission> },
  TContext
> => {
  const mutationKey = ["submitAssessment"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof submitAssessment>>,
    { assessmentId: number; data: BodyType<AssessmentSubmission> }
  > = (props) => {
    const { assessmentId, data } = props ?? {};

    return submitAssessment(assessmentId, data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SubmitAssessmentMutationResult = NonNullable<
  Awaited<ReturnType<typeof submitAssessment>>
>;
export type SubmitAssessmentMutationBody = BodyType<AssessmentSubmission>;
export type SubmitAssessmentMutationError = ErrorType<unknown>;

